    [Button("Start Continuous Microphone")]
    public bool StartContinuousMicrophone()
    {
        if (_isMicrophoneRunning)
        {
            Debug.LogWarning("[MicrophoneInputController] Microphone is already running.");
            return true;
        }

        CacheAvailableMicrophoneDeviceNames();

        if (!HasAnyMicrophoneDevices())
        {
            Debug.LogError("[MicrophoneInputController] No microphone devices were found.");
            return false;
        }

        var microphoneDeviceNameToUse = GetMicrophoneDeviceNameToUse();

        if (!_useDefaultMicrophoneDevice && string.IsNullOrWhiteSpace(microphoneDeviceNameToUse))
        {
            Debug.LogError("[MicrophoneInputController] No microphone selected.");
            return false;
        }

        _activeMicrophoneDeviceName = microphoneDeviceNameToUse;
        _microphoneAudioClip = Microphone.Start(_activeMicrophoneDeviceName, true, _microphoneLoopLengthSeconds, _recordingSampleRate);

        if (_microphoneAudioClip == null)
        {
            Debug.LogError("[MicrophoneInputController] Failed to start continuous microphone recording.");
            CleanupMicrophoneState();
            return false;
        }

        var channelCount = _microphoneAudioClip.channels;
        var ringBufferSampleValueCapacity = _microphoneLoopLengthSeconds * _recordingSampleRate * channelCount;
        _microphoneSampleRingBuffer = new float[ringBufferSampleValueCapacity];
        _ringBufferWriteIndex = 0;
        _totalSampleValuesWritten = 0;
        _lastObservedSamplePositionPerChannel = 0;
        _currentSamplePositionPerChannel = 0;
        _totalSamplesCapturedPerChannel = 0;
        _currentRmsAmplitude = 0.0f;
        _currentPeakAmplitude = 0.0f;
        _isTalkingNow = false;
        _isWaitingForEndTimeout = false;
        _secondsSinceLastDetectedSpeech = 9999.0f;
